const response = $input.first().json;
let text = '';
try {
  text = response.candidates[0].content.parts[0].text.trim();
  // Remove possible markdown code block markers
  if (text.startsWith('```')) {
    text = text.replace(/^```(?:json)?\s*/, '').replace(/```\s*$/, '');
  }
} catch (e) {
  text = JSON.stringify({ error: 'Falha ao processar resposta da IA' });
}

// Parse the JSON string into an object so the backend receives proper JSON
let parsed;
try {
  parsed = JSON.parse(text);
} catch (e) {
  parsed = { raw: text };
}

return [{ json: parsed }];
